/**
 * Fetch wrapper that always sends cookies.
 * Use instead of bare fetch() for all API calls.
 */
function apiFetch(url, opts = {}) {
  return fetch(url, { credentials: 'include', ...opts });
}

function applyBranding({ companyLogo, workspaceName } = {}) {
  const wsTag      = $('ws-name-tag');
  const iconWrap   = $('brand-icon-wrap');

  if (wsTag && workspaceName) wsTag.textContent = workspaceName;

  if (iconWrap) {
    if (companyLogo) {
      iconWrap.innerHTML = `<img src="${companyLogo}" style="max-width:calc(100% - 20px);max-height:calc(100% - 20px);width:auto;height:auto;object-fit:contain;display:block;" onerror="this.parentElement.innerHTML='<svg width=68 height=68 viewBox=&quot;0 0 100 100&quot; fill=none><path d=&quot;M50 3 L63 38 L97 50 L63 62 L50 97 L37 62 L3 50 L37 38 Z&quot; fill=&quot;currentColor&quot;/></svg>'">`;
    } else {
      iconWrap.innerHTML = `<svg width="68" height="68" viewBox="0 0 100 100" fill="none"><path d="M50 3 L63 38 L97 50 L63 62 L50 97 L37 62 L3 50 L37 38 Z" fill="currentColor"/></svg>`;
    }
  }
}

/* ── Workspace launcher: Google-Workspace-style app picker, opened
   by clicking the sidebar logo/brand. ────────────────────────── */
const WS_LAUNCHER_ITEMS = [
  { tab: 'mgmt-dashboard', area: 'management', name: 'Operaciones', desc: 'Proyectos, tareas, clientes y finanzas',
    icon: '<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="3" width="11" height="9" rx="2"/><rect x="16" y="3" width="5" height="9" rx="2"/><rect x="3" y="14" width="5" height="7" rx="2"/><rect x="10" y="14" width="11" height="7" rx="2"/></svg>' },
  { tab: 'single', area: 'enricher', name: 'Enriquecimiento', desc: 'Preparación, verificación y scoring de leads',
    icon: '<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="3"/><path d="M12 3v2.5M12 18.5V21M3 12h2.5M18.5 12H21"/><path d="M6.2 6.2l1.8 1.8M16 16l1.8 1.8M6.2 17.8l1.8-1.8M16 8l1.8-1.8"/></svg>' },
  { tab: 'lead-manager', area: 'leadmanagement', name: 'Outreach', desc: 'CRM, campañas, actividades y seguimiento',
    icon: '<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M22 3H2l8 9.5v7.5l4 2v-9.5L22 3z"/></svg>' },
];

let _wsLauncherClose = null;

function toggleWorkspaceLauncher(e) {
  e.stopPropagation();
  if (_wsLauncherClose) { _wsLauncherClose(); return; }

  const trigger = $('sidebar-brand');
  const sidebar = $('sidebar');
  if (!trigger || !sidebar) return;
  const triggerRect = trigger.getBoundingClientRect();
  const sidebarRect = sidebar.getBoundingClientRect();

  const panel = document.createElement('div');
  panel.className = 'ws-launcher';
  panel.innerHTML = WS_LAUNCHER_ITEMS.map(it => `
    <button class="ws-launcher__item" data-target-tab="${it.tab}" data-target-area="${it.area}">
      <span class="ws-launcher__icon">${it.icon}</span>
      <span class="ws-launcher__body">
        <span class="ws-launcher__name">${it.name}</span>
        <span class="ws-launcher__desc">${it.desc}</span>
      </span>
    </button>
  `).join('');
  document.body.appendChild(panel);

  const top  = Math.max(8, Math.min(triggerRect.top, window.innerHeight - panel.offsetHeight - 8));
  const left = sidebarRect.right + 8;
  panel.style.top  = top + 'px';
  panel.style.left = left + 'px';

  panel.querySelectorAll('.ws-launcher__item').forEach(btn => {
    btn.addEventListener('click', () => {
      selectWorkspaceArea(btn.dataset.targetArea);
      const navBtn = document.querySelector(`.snav-item[data-tab="${btn.dataset.targetTab}"]`);
      if (navBtn) navBtn.click();
      if (_wsLauncherClose) _wsLauncherClose();
    });
  });

  const onDocClick = (ev) => {
    if (!panel.contains(ev.target) && !trigger.contains(ev.target)) _wsLauncherClose();
  };
  const onKeydown = (ev) => { if (ev.key === 'Escape') _wsLauncherClose(); };
  const onScrollOrResize = () => _wsLauncherClose();

  _wsLauncherClose = () => {
    panel.remove();
    document.removeEventListener('click', onDocClick);
    document.removeEventListener('keydown', onKeydown);
    window.removeEventListener('scroll', onScrollOrResize, true);
    window.removeEventListener('resize', onScrollOrResize);
    _wsLauncherClose = null;
  };
  setTimeout(() => {
    document.addEventListener('click', onDocClick);
    document.addEventListener('keydown', onKeydown);
    window.addEventListener('scroll', onScrollOrResize, true);
    window.addEventListener('resize', onScrollOrResize);
  }, 0);
}

/**
 * On page load: call /api/auth/me to determine login state.
 * Shows either the auth wall or the full app.
 */
async function initAuth() {
  const authBar  = $('authBar');
  const authWall = $('authWall');
  const appShell = $('appShell');

  // Detect ?join=TOKEN or ?gcal= in the URL before the auth check
  const urlParams  = new URLSearchParams(window.location.search);
  const joinToken  = urlParams.get('join');
  const gcalParam  = urlParams.get('gcal');
  if (joinToken || gcalParam) history.replaceState(null, '', window.location.pathname);
  if (gcalParam === 'ok')    setTimeout(() => showBanner('✓ Google Calendar conectado — tus eventos aparecerán en el calendario', 'success'), 1200);
  if (gcalParam === 'error') setTimeout(() => showBanner('No se pudo conectar Google Calendar. Inténtalo de nuevo.', 'error'), 800);

  try {
    const res  = await apiFetch(`${API}/auth/me`);
    const data = await res.json();

    if (data.loggedIn) {
      // ── If there's a pending join token, process it first ──
      if (joinToken && !data.workspace_id) {
        try {
          await apiFetch(`${API}/workspace/accept-invite`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ token: joinToken }),
          });
          // Reload so session reflects the new workspace membership
          location.reload();
          return;
        } catch (_) { /* ignore — fall through to normal load */ }
      }

      // ── Apply workspace branding to sidebar ───────────────
      applyBranding(data);

      // ── Brand/logo opens the workspace launcher (all users) ─
      const brand = $('sidebar-brand');
      if (brand) { brand.style.cursor = 'default'; brand.onclick = null; }

      if (data.isOwner) {
        const invBtn = $('invite-btn');
        if (invBtn) invBtn.style.display = '';
      }

      // ── Store auth info globally for modules to read ────────
      window._authUser = data;

      // ── Pie de la barra: nombre + rol del usuario (visible para todos) ──
      const _footUser = document.getElementById('snav-foot-user');
      if (_footUser) {
        const _rol = data.isOwner ? 'Propietaria · Admin'
          : (data.memberRol === 'admin' ? 'Administrador'
          : (data.memberRol === 'manager' ? 'Manager' : 'Miembro'));
        const _nm = data.memberNombre || data.name || 'Usuario';
        const _av = data.avatar || `https://api.dicebear.com/9.x/lorelei/svg?seed=${encodeURIComponent(_nm || data.email || 'user')}`;
        const _avEl = document.getElementById('snav-foot-av');   if (_avEl) _avEl.src = _av;
        const _nmEl = document.getElementById('snav-foot-name'); if (_nmEl) { _nmEl.textContent = _nm; _nmEl.title = _nm; }
        const _roEl = document.getElementById('snav-foot-role'); if (_roEl) _roEl.textContent = _rol;
        _footUser.hidden = false;
      }

      authBar.innerHTML = `
        <img src="${data.avatar || `https://api.dicebear.com/9.x/lorelei/svg?seed=${encodeURIComponent(data.name || data.email || 'user')}`}" alt="" class="rail-user__av" title="${esc(data.name || data.email)}${data.isOwner ? ' · Configuración' : ''}" ${data.isOwner ? 'style="cursor:pointer" onclick="WorkspaceModule.openNameModal()"' : ''}/>
        <div class="ws-user__meta">
          <div class="ws-user__name">${esc(data.name || 'Usuario')}</div>
          <div class="ws-user__mail">${esc(data.email || '')}</div>
        </div>`;

      authWall.classList.add('hidden');
      appShell.classList.remove('hidden');
      initApp();
      // Restaurar la última sección visitada (en vez de volver siempre al Dashboard al recargar).
      // Activamos el pane/nav SÍNCRONAMENTE aquí (antes del await) para que la 1ª pintura ya sea
      // la sección correcta → sin "flash" del Dashboard. Los datos se cargan después de FxRates.
      const _initTab = (() => {
        try { const s = localStorage.getItem('kw_activeTab'); if (s && document.getElementById('pane-' + s) && document.querySelector(`[data-tab="${s}"]`)) return s; } catch (_) {}
        return 'mgmt-dashboard';
      })();
      document.querySelectorAll('.tab,.snav-item').forEach(t => t.classList.toggle('active', t.dataset.tab === _initTab));
      document.querySelectorAll('.pane').forEach(p => p.classList.toggle('active', p.id === 'pane-' + _initTab));
      await FxRatesModule.load();
      if (typeof window._novaSwitchTab === 'function') window._novaSwitchTab(_initTab); else DashboardModule.load();
      ChatModule.init();
      TimerModule.init();

    } else {
      // ── Not logged in ─────────────────────────────────────
      // If there's a join token, show a join banner on the auth wall
      if (joinToken) {
        const joinBanner = document.createElement('div');
        joinBanner.className = 'join-banner';
        joinBanner.innerHTML = `
          <div class="join-banner__title">Te han invitado a un workspace</div>
          <div class="join-banner__sub">Inicia sesión con Google para unirte</div>`;
        const card = authWall.querySelector('.auth-wall__card');
        if (card) card.prepend(joinBanner);
      }

      const loginUrl = joinToken
        ? `${API}/auth/google?join=${encodeURIComponent(joinToken)}`
        : `${API}/auth/google`;

      authBar.innerHTML = `
        <a href="${loginUrl}" class="btn btn--google btn--sm">
          <img src="https://www.gstatic.com/firebasejs/ui/2.0.0/images/auth/google.svg" alt="" width="15" height="15"/>
          Sign in
        </a>`;
      // Also update auth wall button to include join token
      const wallBtn = authWall.querySelector('a[href*="auth/google"]');
      if (wallBtn && joinToken) wallBtn.href = loginUrl;

      authWall.classList.remove('hidden');
      appShell.classList.add('hidden');
    }

  } catch (err) {
    authBar.innerHTML = `<span style="font-size:.78rem;color:var(--err)">⚠ Can't reach server</span>`;
    authWall.classList.remove('hidden');
    appShell.classList.add('hidden');
    console.error('[auth] /api/auth/me failed:', err.message);
  }
}

// ── Show error banner if redirected back with ?error= ─────────────
(function checkUrlError() {
  const params = new URLSearchParams(window.location.search);
  const error  = params.get('error');
  if (!error) return;

  // Clean the query string from the URL without reloading
  history.replaceState(null, '', window.location.pathname);

  const messages = {
    unauthorized: '⛔ Tu cuenta de Google no tiene acceso a esta herramienta. Contactá al administrador.',
    auth_failed:  '⚠️ Hubo un problema al iniciar sesión. Intentá de nuevo.',
  };
  const msg = messages[error] || `Error de autenticación: ${error}`;

  // Inject a dismissible banner above the auth wall
  const banner = document.createElement('div');
  banner.style.cssText = [
    'position:fixed;top:0;left:0;right:0;z-index:300',
    'background:#7f1d1d;color:#fff;font-size:.85rem;font-weight:600',
    'padding:13px 20px;display:flex;align-items:center;justify-content:space-between',
    'gap:12px;box-shadow:0 2px 8px rgba(0,0,0,.25)',
  ].join(';');
  banner.innerHTML = `<span>${msg}</span>
    <button style="background:rgba(255,255,255,.2);border:none;border-radius:6px;
      color:#fff;padding:4px 12px;cursor:pointer;font-size:.8rem;font-weight:600"
      onclick="this.parentElement.remove()">Cerrar</button>`;
  document.body.prepend(banner);
})();

// ── Global exchange rates ─────────────────────────────────────────
window._fxRates = {};   // { PEN: 3.70, COP: 4200, ... }  1 USD = X moneda

// ── Multi-responsable chip helpers (global) ───────────────────────
function _respToggle(el, wrapId) {
  el.classList.toggle('resp-chip--on');
  const wrap = document.getElementById(wrapId);
  const hidden = document.getElementById(wrapId.replace('-chips', 's-val'));
  if (!hidden) return;
  hidden.value = JSON.stringify(
    [...wrap.querySelectorAll('.resp-chip--on')].map(c => c.dataset.name)
  );
}

async function _loadRespChips(wrapId, selected = []) {
  const wrap = document.getElementById(wrapId);
  if (!wrap) return;
  wrap.innerHTML = '<span class="resp-loading">Cargando…</span>';
  try {
    const res = await apiFetch(`${API}/mgmt/team`);
    const members = res.ok ? await res.json() : [];
    const hidden = document.getElementById(wrapId.replace('-chips', 's-val'));
    if (!members.length) {
      wrap.innerHTML = '<span class="resp-loading">Sin miembros en el equipo</span>';
      return;
    }
    wrap.innerHTML = members.map(m => {
      const on = selected.includes(m.nombre);
      return `<button type="button" class="resp-chip${on ? ' resp-chip--on' : ''}"
        data-name="${esc(m.nombre)}" onclick="_respToggle(this,'${wrapId}')"
        >${esc(m.nombre)}</button>`;
    }).join('');
    if (hidden) hidden.value = JSON.stringify(selected);
  } catch {
    wrap.innerHTML = '<span class="resp-loading">Error al cargar</span>';
  }
}

function _respVal(hiddenId) {
  try { return JSON.parse(document.getElementById(hiddenId)?.value || '[]'); }
  catch { return []; }
}

// Sidebar workspace groups: Management / Enricher / Lead Management.
// Manual toggle (chevron click) only opens/closes that one group.
// Selecting an area from the logo launcher (selectWorkspaceArea) instead
// expands that group and collapses the other two — see toggleWorkspaceLauncher.
const SNAV_GROUPS = ['management', 'enricher', 'leadmanagement'];

function _loadExpandedGroups() {
  try {
    const saved = JSON.parse(localStorage.getItem('sb-expanded-groups') || 'null');
    if (saved && typeof saved === 'object') return saved;
  } catch (_) {}
  return { management: true, enricher: false, leadmanagement: false };
}

function _applyExpandedGroups(state) {
  SNAV_GROUPS.forEach(id => {
    const body = document.getElementById('snav-body-' + id);
    const hdr  = document.getElementById('snav-hdr-' + id);
    if (!body || !hdr) return;
    const expanded = !!state[id];
    body.classList.toggle('snav-section-body--collapsed', !expanded);
    hdr.setAttribute('aria-expanded', String(expanded));
  });
}

function selectWorkspaceArea(area) {
  const state = { management: area === 'management', enricher: area === 'enricher', leadmanagement: area === 'leadmanagement' };
  _applyExpandedGroups(state);
  localStorage.setItem('sb-expanded-groups', JSON.stringify(state));
}

// ── Doble sidebar: rail de módulos + panel de secciones ──
let _activeModule = 'management';
const _MOD_TITLES = { management: 'Operaciones', enricher: 'Enriquecimiento', leadmanagement: 'Outreach' };
function _moduleOf(tab) {
  return document.querySelector(`.snav-item[data-tab="${tab}"]`)?.closest('.snav-group')?.dataset.module || 'management';
}
function _setActiveModule(mod) {
  _activeModule = mod;
  document.querySelectorAll('.snav-mod').forEach(b => b.classList.toggle('active', b.dataset.module === mod));
  document.querySelectorAll('.snav-group').forEach(g => g.classList.toggle('mod-on', g.dataset.module === mod));
  const t = document.getElementById('snav-panel-title'); if (t) t.textContent = _MOD_TITLES[mod] || '';
  // Lead Management usa su barra interna → oculta el panel redundante del rail
  document.getElementById('appShell')?.classList.toggle('lm-active', mod === 'leadmanagement');
}
function _navCollapsed() { return !!document.getElementById('appShell')?.classList.contains('nav-collapsed'); }
function _setNavCollapsed(on) {
  document.getElementById('appShell')?.classList.toggle('nav-collapsed', on);
  try { localStorage.setItem('sb-collapsed', on ? '1' : '0'); } catch (_) {}
}
function toggleNavPanel() { _setNavCollapsed(!_navCollapsed()); }
function selectModule(mod) {
  if (_navCollapsed()) _setNavCollapsed(false);
  _setActiveModule(mod);
  let target = null;
  try { target = localStorage.getItem('kw_lastTab_' + mod); } catch (_) {}
  const group = document.getElementById('snav-body-' + mod);
  if (!target || !group?.querySelector(`.snav-item[data-tab="${target}"]`)) target = group?.querySelector('.snav-item')?.dataset.tab;
  if (target && typeof window._novaSwitchTab === 'function') window._novaSwitchTab(target);
}

// ── Menú de workspace (cambiar de módulo) ──────────────────
let _wsMenuOpen = false;
function toggleWorkspaceMenu(btn) {
  const menu = document.getElementById('ws-menu');
  if (!menu) return;
  if (_wsMenuOpen) { closeWorkspaceMenu(); return; }
  // (El usuario ya se muestra en el pie de la barra — no se duplica en este menú.)
  // Marca el módulo activo dentro del menú
  menu.querySelectorAll('.ws-mod').forEach(b => b.classList.toggle('active', b.dataset.module === _activeModule));
  // Posiciona bajo el botón, sin salirse de la pantalla
  const r = btn.getBoundingClientRect();
  menu.classList.remove('hidden');
  const mw = menu.offsetWidth || 248;
  let left = r.left;
  if (left + mw > window.innerWidth - 8) left = window.innerWidth - mw - 8;
  menu.style.top = (r.bottom + 6) + 'px';
  menu.style.left = Math.max(8, left) + 'px';
  _wsMenuOpen = true;
  setTimeout(() => document.addEventListener('mousedown', _wsMenuOutside), 0);
}
function _wsMenuOutside(e) {
  const menu = document.getElementById('ws-menu');
  if (menu && !menu.contains(e.target) && !e.target.closest('.snav-ws')) closeWorkspaceMenu();
}
function closeWorkspaceMenu() {
  const menu = document.getElementById('ws-menu');
  if (menu) menu.classList.add('hidden');
  _wsMenuOpen = false;
  document.removeEventListener('mousedown', _wsMenuOutside);
}
// Cerrar sesión desde el pie fijo de la barra (Salir de la cuenta)
function novaLogout(e) {
  if (e) { e.preventDefault(); e.stopPropagation(); }
  try {
    apiFetch(`${API}/auth/logout`).then(() => location.reload()).catch(() => location.reload());
  } catch (_) { location.href = `${API}/auth/logout`; }
}

// Simple top toast
function snavToggle(id) {
  const body = document.getElementById('snav-body-' + id);
  const hdr  = document.getElementById('snav-hdr-' + id);
  if (!body || !hdr) return;
  const isOpen = !body.classList.contains('snav-section-body--collapsed');
  body.classList.toggle('snav-section-body--collapsed', isOpen);
  hdr.setAttribute('aria-expanded', String(!isOpen));
  if (SNAV_GROUPS.includes(id)) {
    const state = _loadExpandedGroups();
    state[id] = !isOpen;
    localStorage.setItem('sb-expanded-groups', JSON.stringify(state));
  }
}

function showBanner(msg, type) {
  const el = document.createElement('div');
  const bg = type === 'success' ? '#166534' : type === 'error' ? '#7f1d1d' : '#1e3a5f';
  el.style.cssText = `position:fixed;top:0;left:0;right:0;z-index:9999;background:${bg};color:#fff;font-size:.84rem;font-weight:600;padding:11px 20px;display:flex;align-items:center;justify-content:space-between;gap:12px;box-shadow:0 2px 8px rgba(0,0,0,.2);animation:slideDown .2s ease`;
  el.innerHTML = `<span>${msg}</span><button onclick="this.parentElement.remove()" style="background:rgba(255,255,255,.18);border:none;border-radius:5px;color:#fff;padding:3px 10px;cursor:pointer;font-size:.78rem">✕</button>`;
  document.body.prepend(el);
  setTimeout(() => el.remove(), 5000);
}

